SELECT org_name, total_funding_amount
FROM organizations
ORDER BY total_funding_amount DESC;

SELECT usage_count
FROM api_keys
WHERE api_key = 'key123456789';

SELECT org_name
FROM organizations
ORDER BY org_name;

SELECT number_of_employees AS total_employees
FROM organizations
WHERE org_id = 0;

SELECT COUNT(*) AS report_count
FROM research_reports
WHERE org_id = 1;

SELECT SUM(download_count) AS total_downloads
FROM research_reports
WHERE report_id = 0;

SELECT org_name
FROM organizations
WHERE total_funding_amount > (SELECT AVG(total_funding_amount) FROM organizations);
